import fs from 'node:fs';
import path from 'node:path';
import { codexHome } from '../paths.js';
/**
 * Codex does not have a settings entry pointing at external files; it scans
 * ~/.codex/ (or $CODEX_HOME). Writing to AGENTS.override.md (precedence above
 * AGENTS.md) avoids clobbering a file the user may already maintain at the
 * default AGENTS.md path.
 *
 * Try to install as a symlink first (single source of truth — edits to the
 * generated file propagate instantly). If symlinks are not allowed (Windows
 * without Developer Mode, some sandboxes), fall back to a plain copy tagged
 * with a marker so we can recognise our own output at uninstall.
 */
export function runCodex(profile, artifacts, opts = {}) {
    const home = codexHome(opts.codexHome);
    const target = path.join(home, 'AGENTS.override.md').split(path.sep).join('/');
    const source = artifacts.agentsMd;
    const ownedMarker = `<!-- agent-toolbox:${profile.name}:codex -->`;
    if (opts.uninstall) {
        if (!fs.existsSync(target)) {
            return { surface: 'codex', action: 'noop', detail: `no file at ${target}` };
        }
        if (!isOwned(target, ownedMarker)) {
            return {
                surface: 'codex',
                action: 'noop',
                detail: `${target} exists but is not owned by agent-toolbox; leaving it alone`,
            };
        }
        if (opts.dryRun) {
            return { surface: 'codex', action: 'planned', detail: `would remove ${target}` };
        }
        fs.rmSync(target);
        return { surface: 'codex', action: 'remove', detail: `removed ${target}` };
    }
    if (!fs.existsSync(source)) {
        throw new Error(`Generator output missing: ${source}`);
    }
    if (fs.existsSync(target) && !isOwned(target, ownedMarker)) {
        throw new Error(`${target} already exists and is not owned by agent-toolbox. Move or delete it before installing the codex surface.`);
    }
    if (opts.dryRun) {
        return {
            surface: 'codex',
            action: 'planned',
            detail: `would link or copy ${source} → ${target}`,
        };
    }
    fs.mkdirSync(home, { recursive: true });
    // Remove any prior install (could be a stale symlink pointing elsewhere).
    if (fs.existsSync(target) || isBrokenSymlink(target)) {
        fs.rmSync(target, { force: true });
    }
    try {
        fs.symlinkSync(source, target, 'file');
        return {
            surface: 'codex',
            action: 'append',
            detail: `symlinked ${target} → ${source}`,
        };
    }
    catch {
        // Fallback: copy, and stamp the file with an owned marker the uninstall
        // code can recognise (the source already includes this marker via
        // generator output — confirm and re-emit if absent).
        const body = fs.readFileSync(source, 'utf8');
        const stamped = body.includes(ownedMarker) ? body : `${ownedMarker}\n${body}`;
        fs.writeFileSync(target, stamped, 'utf8');
        return {
            surface: 'codex',
            action: 'append',
            detail: `copied ${source} to ${target} (symlink not permitted on this host)`,
        };
    }
}
function isOwned(file, marker) {
    try {
        const stat = fs.lstatSync(file);
        if (stat.isSymbolicLink()) {
            // A symlink we created will point at a path under ~/.agent-toolbox/generated.
            const linkTarget = fs.readlinkSync(file);
            return linkTarget.includes('.agent-toolbox/generated') || linkTarget.includes('agent-toolbox\\generated');
        }
    }
    catch {
        return false;
    }
    try {
        const body = fs.readFileSync(file, 'utf8');
        return body.includes(marker) || body.includes('<!-- GENERATED by agent-toolbox');
    }
    catch {
        return false;
    }
}
function isBrokenSymlink(file) {
    try {
        const stat = fs.lstatSync(file);
        return stat.isSymbolicLink();
    }
    catch {
        return false;
    }
}
